let slide=document.getElementById('slide-content'),audio=document.getElementById('audio-content'),audioUrl=audio.getAttribute('data-audio');function next(){let a=slide.getAttribute('data-slide'),b=parseInt(slide.getAttribute('data-max'));if(a<b){let b=window.location.href+'slide/slide-'+(parseInt(a)+1)+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+(parseInt(a)+1)+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide",parseInt(a)+1)}}function prev(){let a=slide.getAttribute('data-slide');if(a>1){let b=window.location.href+'slide/slide-'+(parseInt(a)-1)+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+(parseInt(a)-1)+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide",parseInt(a)-1)}else{let b=window.location.href+'slide/slide-'+a+'.jpg',c='https://archive.org/download/'+audioUrl+'/slide-'+a+'.mp3';slide.src=b,audio.src=c,audio.load(),audio.play(),slide.setAttribute("data-slide","1")}}document.getElementById("next-slide").addEventListener("click",function(){next()}),document.getElementById("prev-slide").addEventListener("click",function(){prev()}),audio.onended=function(){next()}